import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.BPmc_f4o.js";const p=JSON.parse('{"title":"Auth Hardening","description":"","frontmatter":{},"headers":[],"relativePath":"login-hardening/login-hardening.md","filePath":"login-hardening/login-hardening.md"}'),i={name:"login-hardening/login-hardening.md"};function r(s,e,l,d,h,g){return t(),n("div",null,[...e[0]||(e[0]=[o('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#2e7d32;color:#fff;font-size:11px;font-weight:600;">FREE</span> <span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="auth-hardening" tabindex="-1">Auth Hardening <a class="header-anchor" href="#auth-hardening" aria-label="Permalink to &quot;Auth Hardening&quot;">​</a></h1><p>Auth Hardening protects the WordPress login surface against brute-force attempts. This panel is separate from REST API traffic quotas and is available in both Free and Pro.</p><hr><h2 id="what-it-controls" tabindex="-1">What It Controls <a class="header-anchor" href="#what-it-controls" aria-label="Permalink to &quot;What It Controls&quot;">​</a></h2><ul><li><strong>Enable Login Rate Limiting</strong>: turns login protection on/off.</li><li><strong>Max Failed Attempts</strong>: number of failed logins allowed before block.</li><li><strong>Window (seconds)</strong>: rolling period used to count failed attempts.</li><li><strong>Block Duration (seconds)</strong>: temporary block duration once threshold is exceeded.</li><li><strong>Escalation Threshold</strong>: optional promotion behavior after repeated block cycles.</li></ul><hr><h2 id="recommended-baseline" tabindex="-1">Recommended Baseline <a class="header-anchor" href="#recommended-baseline" aria-label="Permalink to &quot;Recommended Baseline&quot;">​</a></h2><ol><li>Enable login rate limiting.</li><li>Start with conservative defaults (for example 5 attempts / 300s).</li><li>Use a meaningful block duration (for example 3600s).</li><li>Monitor behavior in Logs and adjust for your audience.</li></ol><hr><h2 id="pro-and-headless-context" tabindex="-1">Pro and Headless Context <a class="header-anchor" href="#pro-and-headless-context" aria-label="Permalink to &quot;Pro and Headless Context&quot;">​</a></h2><p>In Pro deployments using <a href="/wordpress-mode/wordpress-mode.html">WordPress Mode</a>, trusted IPs can bypass lockout-sensitive enforcement paths. Keep this list minimal and limited to known operators.</p><hr><h2 id="auth-hardening-vs-rest-rate-limiting" tabindex="-1">Auth Hardening vs REST Rate Limiting <a class="header-anchor" href="#auth-hardening-vs-rest-rate-limiting" aria-label="Permalink to &quot;Auth Hardening vs REST Rate Limiting&quot;">​</a></h2><ul><li><strong>Auth Hardening</strong>: protects the WordPress login flow.</li><li><strong>Auth &amp; Rate Limiting panel</strong>: protects REST API usage patterns.</li><li><strong>Global IP Filtering</strong>: blocks abusive sources before deeper policy checks.</li></ul><p>Use all three layers together for best results.</p>',16)])])}const u=a(i,[["render",r]]);export{p as __pageData,u as default};
